mapper.insert:
insert into asterisk.ps_endpoints (id, transport, aors, auth, context, disallow, allow, record_yn, callerid)
values (#{id}, #{transport}, #{id}, #{id}, #{context}, 'all', #{allow}, coalesce(#{record_yn}, 'y'), #{callerid})
on duplicate key update transport = #{transport}, context = #{context}, allow = #{allow}, record_yn = coalesce(#{record_yn}, 'y'), callerid = #{callerid}

mapper.delete:
delete from asterisk.ps_endpoints where id = #{id};
delete from asterisk.ps_auths where id = #{id};
delete from asterisk.ps_aors where id = #{id};

mapper.insert:
insert into asterisk.queues (name, musiconhold, strategy, timeout, ringinuse, context)
values (#{name}, coalesce(#{musiconhold}, 'default'), #{strategy}, #{timeout}, #{ringinuse}, #{context})
on duplicate key update musiconhold = coalesce(#{musiconhold}, 'default'), strategy = #{strategy}, timeout = #{timeout}
